	public function get_comments($filter = array())
	{
		$id_filter = '';
		$order_id_filter = '';
		$user_id_filter = '';
		$block_filter = '';
        $keyword_filter = '';
        $exclude_block_filter = '';
        $created_filter = '';
        $limit = 1000;
		$page = 1;
        
        if (!empty($filter['id']))
            $id_filter = $this->db->placehold("AND id IN (?@)", array_map('intval', (array)$filter['id']));
        
        if (!empty($filter['user_id']))
            $user_id_filter = $this->db->placehold("AND user_id = ?", (int)$filter['user_id']);
		
        if (!empty($filter['order_id']))
            $order_id_filter = $this->db->placehold("AND order_id = ?", (int)$filter['order_id']);

        if (!empty($filter['block']))
            $block_filter = $this->db->placehold("AND block = ?", (string)$filter['block']);

        // Фильтр на исключение определенных block
        if (!empty($filter['exclude_block'])) {
            $exclude_blocks = array_map('strval', (array)$filter['exclude_block']);
            $exclude_block_filter = $this->db->placehold("AND block NOT IN (?@)", $exclude_blocks);
        }

        if (!empty($filter['created'])){
            $startOfDay = date('Y-m-d 00:00:00', strtotime($filter['created']));
            $endOfDay = date('Y-m-d 23:59:59', strtotime($filter['created']));
            $created_filter = $this->db->placehold("AND created BETWEEN ? AND ?", $startOfDay, $endOfDay);
        }

        if(isset($filter['keyword']))
		{
			$keywords = explode(' ', $filter['keyword']);
			foreach($keywords as $keyword)
				$keyword_filter .= $this->db->placehold('AND (name LIKE "%'.$this->db->escape(trim($keyword)).'%" )');
		}
        
		if(isset($filter['limit']))
			$limit = max(1, intval($filter['limit']));

		if(isset($filter['page']))
			$page = max(1, intval($filter['page']));
            
        $sql_limit = $this->db->placehold(' LIMIT ?, ? ', ($page-1)*$limit, $limit);

        $query = $this->db->placehold("
            SELECT 
                c.*,
                m.name as manager_name
            FROM s_comments c
            LEFT JOIN __managers m ON c.manager_id = m.id
            WHERE 1
                $id_filter
        		$order_id_filter
        		$user_id_filter 
                $keyword_filter
                $block_filter
                $exclude_block_filter
                $created_filter
            ORDER BY id DESC 
            $sql_limit
        ");
        
        $this->db->query($query);
        
        return $this->db->results();
	}
    
	public function count_comments($filter = array())
	{
        $id_filter = '';
		$order_id_filter = '';
		$user_id_filter = '';
        $keyword_filter = '';
        
        if (!empty($filter['id']))
            $id_filter = $this->db->placehold("AND id IN (?@)", array_map('intval', (array)$filter['id']));
		
        if (!empty($filter['user_id']))
            $user_id_filter = $this->db->placehold("AND user_id = ?", (int)$filter['user_id']);
		
        if (!empty($filter['order_id']))
            $order_id_filter = $this->db->placehold("AND order_id = ?", (int)$filter['order_id']);
		
        if(isset($filter['keyword']))
		{
			$keywords = explode(' ', $filter['keyword']);
			foreach($keywords as $keyword)
				$keyword_filter .= $this->db->placehold('AND (name LIKE "%'.$this->db->escape(trim($keyword)).'%" )');
		}
                
		$query = $this->db->placehold("
            SELECT COUNT(id) AS count
            FROM __comments
            WHERE 1
                $id_filter
        		$order_id_filter
        		$user_id_filter 
                $keyword_filter
        ");
        $this->db->query($query);
        $count = $this->db->result('count');
	
        return $count;
    }
    
