    public function add_action_log($user_id, $manager_id, $action, $order_id = '')
    {
        if ($action == 'block')
            $text = 'Блокировка/удаление личного кабинета';
        elseif ($action == 'unblock')
            $text = 'Снятие блокировки/удаления';

        if (!$text)
            return;

        $block = 'order';
        $this->add_comment_log($user_id, $manager_id, $block, $text, $order_id);
    }

    public function add_field_log($user_id, $manager_id, $field_name, $old_value, $new_value, $block = 'personal', $order_id = '')
    {
        $text = "Смена " . $field_name . " с " . $old_value . " на " . $new_value;
        $this->add_comment_log($user_id, $manager_id, $block, $text, $order_id);
    }

    private function add_comment_log($user_id, $manager_id, $block, $text, $order_id = '')
    {
        $manager_id = $manager_id ?? $this->managers::MANAGER_SYSTEM_ID;
        $comment = [
            'manager_id' => $manager_id,
            'user_id' => $user_id,
            'block' => $block,
            'text' => $text,
            'created' => date('Y-m-d H:i:s'),
            'order_id' => $order_id
        ];
        if ($this->comments->add_comment($comment))
        {
            if (!empty($order_id))
                $order = $this->orders->get_order((int)$order_id);

            $manager = $this->managers->get_manager($manager_id);
            $user = $this->users->get_user($user_id);

            $this->soap->send_comment([
                'manager' => $manager->name_1c,
                'text' => $text,
                'created' => date('Y-m-d H:i:s'),
                'number' => $order->id_1c ?? '',
                'user_uid' => empty($order) ? $user->UID : ''
            ]);
        }
    }

    public function get_comments_without_analysis($dateFrom, $dateTo)
    {
        $query = $this->db->placehold("
            SELECT 
                s_comments.id,
                s_comments.user_id,
                s_comments.block,
                s_comments.created,
                s_comments.text
            FROM s_comments
            LEFT JOIN s_comment_record_analysis ON s_comments.id = s_comment_record_analysis.comment_id
            WHERE
                    s_comments.created BETWEEN '".$dateFrom."' AND '".$dateTo."'
                AND s_comments.block IN ('".CommentBlocks::INCOMING_CALL."', '".CommentBlocks::OUTGOING_CALL."') 
                AND s_comment_record_analysis.comment_id IS NULL 
                AND s_comments.text LIKE '%\"is_sent_analysis\":false%'
            ");
        $this->db->query($query);

        return $this->db->results();
    }

